import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  RotateCcw, Settings, AlertCircle, 
  Keyboard, Download, 
  BarChart3, History, Zap, Hash
} from 'lucide-react';

// Types
type TestMode = 'time' | 'words' | 'quote' | 'zen' | 'custom';
type TestLanguage = 'english' | 'french' | 'spanish' | 'german' | 'javascript' | 'python' | 'typescript' | 'java' | 'cpp' | 'rust' | 'go' | 'html' | 'css' | 'php' | 'csharp';
type TestDifficulty = 'normal' | 'expert' | 'master';

interface TestStats {
  wpm: number;
  rawWpm: number;
  accuracy: number;
  consistency: number;
  correctChars: number;
  incorrectChars: number;
  missedChars: number;
  extraChars: number;
  keyStats: Record<string, { correct: number; incorrect: number }>;
  fingerStats: Record<string, { correct: number; incorrect: number; weakness: boolean }>;
  weakKeys: string[];
  mostMissedWords: string[];
  testDuration: number;
  timestamp: number;
  language: TestLanguage;
  mode: TestMode;
  difficulty: TestDifficulty;
}

interface UserProfile {
  totalTests: number;
  totalTimeSpent: number; // in seconds
  averageWpm: number;
  bestWpm: number;
  averageAccuracy: number;
  testHistory: TestStats[];
  weakFingers: string[];
  weakKeys: string[];
  mostMissedWords: string[];
  currentStreak: number;
  longestStreak: number;
}

